effects.wgsl:
fn fl_state(c: vec2f) -> vec4f { return textureSampleLevel(feedbackTex, texSampler, feedbackUV(c), 0.0); }
fn fl_vel(s: vec4f) -> vec2f { return (s.rg - 0.5) * 8.0; }        // decode ±4 cells/step
fn fl_enc_vel(v: vec2f) -> vec2f { return clamp(v / 8.0 + 0.5, vec2f(0.0), vec2f(1.0)); }

fn fieldEffect(coord: vec2f, regionMin: vec2f, regionMax: vec2f, time: f32, params: vec4f) -> vec4f {
  let dt = 0.9;
  let self = fl_state(coord);
  var vel = fl_vel(self);
  var pres = (self.a - 0.5) * 4.0;

  // neighbours (one cell)
  let sL = fl_state(coord + vec2f(-1.0, 0.0));
  let sR = fl_state(coord + vec2f( 1.0, 0.0));
  let sD = fl_state(coord + vec2f( 0.0,-1.0));
  let sU = fl_state(coord + vec2f( 0.0, 1.0));

  // 1 — semi-Lagrangian advection: trace back along velocity, resample
  let back = coord - vel * dt;
  let adv = fl_state(back);
  vel = fl_vel(adv);
  var dye = adv.b;

  // 2 — emitters: two swirling jets keep the fluid alive
  let t = time;
  let e1 = regionMin + (regionMax - regionMin) * vec2f(0.30, 0.35);
  let e2 = regionMin + (regionMax - regionMin) * vec2f(0.70, 0.62);
  let span = (regionMax.x - regionMin.x);
  let d1 = length(coord - e1) / span;
  let d2 = length(coord - e2) / span;
  vel += vec2f( cos(t * 0.9),  sin(t * 0.9)) * exp(-d1 * d1 * 120.0) * 3.2;
  vel += vec2f(-sin(t * 0.7),  cos(t * 0.7)) * exp(-d2 * d2 * 120.0) * 3.2;
  dye += exp(-d1 * d1 * 160.0) * 0.6 + exp(-d2 * d2 * 160.0) * 0.6;

  // 3 — divergence of the (advected + forced) velocity field
  let vL = fl_vel(sL); let vR = fl_vel(sR); let vDn = fl_vel(sD); let vUp = fl_vel(sU);
  let div = 0.5 * ((vR.x - vL.x) + (vUp.y - vDn.y));

  // 4 — ONE Jacobi pressure iteration (amortized across frames)
  let pL = (sL.a - 0.5) * 4.0; let pR = (sR.a - 0.5) * 4.0;
  let pDn = (sD.a - 0.5) * 4.0; let pUp = (sU.a - 0.5) * 4.0;
  pres = (pL + pR + pDn + pUp - div) * 0.25;

  // 5 — subtract pressure gradient → incompressible flow
  vel -= vec2f(pR - pL, pUp - pDn) * 0.5;

  // gentle dissipation so nothing blows up
  vel *= 0.995;
  dye = clamp(dye * 0.985, 0.0, 1.4);

  return vec4f(fl_enc_vel(vel), dye, clamp(pres / 4.0 + 0.5, 0.0, 1.0));
}

